import{_ as e,o as n,c as t,aw as r}from"./chunks/framework.Dq2onT5h.js";const s=JSON.parse('{"title":"Sequencing","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Sequencing | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"concepts/sequencing.md","filePath":"concepts/sequencing.md","lastUpdated":1772446570000}');const a=e({name:"concepts/sequencing.md"},[["render",function(e,s,a,i,o,l){return n(),t("div",null,[...s[0]||(s[0]=[r('<h1 id="sequencing" tabindex="-1">Sequencing <a class="header-anchor" href="#sequencing" aria-label="Permalink to &quot;Sequencing&quot;">​</a></h1><p>Sequencing is the process of determining the order of transactions in a blockchain. In rollups, the sequencer is the entity responsible for collecting transactions from users, ordering them, and producing blocks that are eventually posted to the data availability (DA) layer.</p><p>Transaction ordering matters because it determines execution outcomes. Two transactions that touch the same state can produce different results depending on which executes first. The sequencer&#39;s ordering decisions directly impact users, particularly in DeFi where transaction order can mean the difference between a successful trade and a failed one.</p><h2 id="the-role-of-the-sequencer" tabindex="-1">The Role of the Sequencer <a class="header-anchor" href="#the-role-of-the-sequencer" aria-label="Permalink to &quot;The Role of the Sequencer&quot;">​</a></h2><p>A sequencer performs three core functions:</p><ol><li><strong>Transaction collection</strong> — Accepting transactions from users and holding them in a mempool</li><li><strong>Ordering</strong> — Deciding which transactions to include and in what order</li><li><strong>Block production</strong> — Bundling ordered transactions into blocks and publishing them</li></ol><p>In traditional L1 blockchains, these functions are distributed across validators through consensus. In rollups, sequencing can be handled differently depending on the design goals.</p><h2 id="single-sequencer" tabindex="-1">Single Sequencer <a class="header-anchor" href="#single-sequencer" aria-label="Permalink to &quot;Single Sequencer&quot;">​</a></h2><p>The simplest approach is a single sequencer: one designated node that orders all transactions.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User → Sequencer → Block → DA Layer</span></span></code></pre></div><p><strong>Advantages:</strong></p><ul><li><strong>Low latency</strong> — No consensus required means block times can be very fast (sub-second)</li><li><strong>Simple operation</strong> — One node, one source of truth for ordering</li><li><strong>Predictable performance</strong> — No coordination overhead</li></ul><p><strong>Disadvantages:</strong></p><ul><li><strong>Centralization</strong> — Single point of control over transaction ordering</li><li><strong>Censorship risk</strong> — The sequencer can refuse to include specific transactions</li><li><strong>Liveness dependency</strong> — If the sequencer goes down, the chain halts</li><li><strong>MEV extraction</strong> — The sequencer has full visibility and can reorder for profit</li></ul><p>Most production rollups today use single sequencers because the performance benefits are significant and the trust assumptions are often acceptable for their use cases.</p><h2 id="based-sequencing" tabindex="-1">Based Sequencing <a class="header-anchor" href="#based-sequencing" aria-label="Permalink to &quot;Based Sequencing&quot;">​</a></h2><p>Based sequencing (also called &quot;based rollups&quot;) delegates transaction ordering to the underlying DA layer. Instead of a dedicated sequencer, users submit transactions directly to the DA layer, and all rollup nodes independently derive the same ordering from DA blocks.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User → DA Layer → All Nodes Derive Same Order</span></span></code></pre></div><p><strong>Advantages:</strong></p><ul><li><strong>Decentralization</strong> — No privileged sequencer role</li><li><strong>Censorship resistance</strong> — Inherits the censorship resistance of the DA layer</li><li><strong>Liveness</strong> — Chain stays live as long as the DA layer is live</li><li><strong>Shared security</strong> — Ordering is secured by the DA layer&#39;s consensus</li></ul><p><strong>Disadvantages:</strong></p><ul><li><strong>Higher latency</strong> — Block times are bounded by DA layer block times (e.g., ~12s for Ethereum, ~6s for Celestia)</li><li><strong>MEV leakage</strong> — MEV flows to DA layer validators rather than the rollup</li><li><strong>Complexity</strong> — Requires deterministic derivation rules that all nodes must follow</li></ul><p>Based sequencing is compelling for applications that prioritize decentralization over speed.</p><h2 id="hybrid-approaches" tabindex="-1">Hybrid Approaches <a class="header-anchor" href="#hybrid-approaches" aria-label="Permalink to &quot;Hybrid Approaches&quot;">​</a></h2><h3 id="forced-inclusion" tabindex="-1">Forced Inclusion <a class="header-anchor" href="#forced-inclusion" aria-label="Permalink to &quot;Forced Inclusion&quot;">​</a></h3><p>Forced inclusion is a mechanism that combines the performance of single sequencing with censorship resistance guarantees. It works as follows:</p><ol><li>Users normally submit transactions to the sequencer for fast inclusion</li><li>If censored, users can submit transactions directly to the DA layer</li><li>The sequencer must include DA-submitted transactions within a defined time window</li><li>Failure to include triggers penalties or allows the chain to transition to based mode</li></ol><p>This gives users an escape hatch while maintaining the benefits of centralized sequencing for the common case.</p><h3 id="shared-sequencing" tabindex="-1">Shared Sequencing <a class="header-anchor" href="#shared-sequencing" aria-label="Permalink to &quot;Shared Sequencing&quot;">​</a></h3><p>Multiple rollups can share a sequencer or sequencer network. This enables:</p><ul><li><strong>Atomic cross-rollup transactions</strong> — Transactions that span multiple rollups can be ordered atomically</li><li><strong>Shared MEV</strong> — Revenue from cross-rollup MEV can be distributed</li><li><strong>Reduced costs</strong> — Infrastructure costs are amortized across chains</li></ul><p>Shared sequencing is an active area of research and development.</p><h2 id="mev-considerations" tabindex="-1">MEV Considerations <a class="header-anchor" href="#mev-considerations" aria-label="Permalink to &quot;MEV Considerations&quot;">​</a></h2><p>Maximal Extractable Value (MEV) is the profit a sequencer can extract by reordering, inserting, or censoring transactions. Common MEV strategies include:</p><ul><li><strong>Frontrunning</strong> — Inserting a transaction before a target transaction</li><li><strong>Backrunning</strong> — Inserting a transaction immediately after a target</li><li><strong>Sandwich attacks</strong> — Combining frontrunning and backrunning around a target</li></ul><p>The sequencing design determines who captures MEV:</p><table tabindex="0"><thead><tr><th>Design</th><th>MEV Captured By</th></tr></thead><tbody><tr><td>Single sequencer</td><td>Sequencer operator</td></tr><tr><td>Based sequencing</td><td>DA layer validators</td></tr><tr><td>Shared sequencing</td><td>Shared sequencer network</td></tr></tbody></table><p>Some rollups implement MEV mitigation through encrypted mempools, fair ordering protocols, or MEV redistribution to users.</p><h2 id="choosing-a-sequencing-model" tabindex="-1">Choosing a Sequencing Model <a class="header-anchor" href="#choosing-a-sequencing-model" aria-label="Permalink to &quot;Choosing a Sequencing Model&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Factor</th><th>Single Sequencer</th><th>Based Sequencer</th></tr></thead><tbody><tr><td>Block time</td><td>Sub-second possible</td><td>DA layer block time</td></tr><tr><td>Censorship resistance</td><td>Requires forced inclusion</td><td>Native</td></tr><tr><td>Liveness</td><td>Sequencer must be online</td><td>DA layer liveness</td></tr><tr><td>MEV control</td><td>Sequencer controlled</td><td>DA layer controlled</td></tr><tr><td>Operational complexity</td><td>Lower</td><td>Higher</td></tr></tbody></table><p>The right choice depends on your application&#39;s priorities. High-frequency trading applications might prefer single sequencing for speed. Applications handling high-value, censorship-sensitive transactions might prefer based sequencing for its guarantees.</p><h2 id="learn-more" tabindex="-1">Learn More <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn More&quot;">​</a></h2><ul><li><a href="/guides/advanced/forced-inclusion">Forced Inclusion</a> — Implementing censorship resistance with single sequencing</li><li><a href="/guides/advanced/based-sequencing">Based Sequencing</a> — Running a based rollup</li><li><a href="/reference/interfaces/sequencer">Sequencer Interface</a> — Implementation reference</li></ul>',43)])])}]]);export{s as __pageData,a as default};
